@param {string} [props.iconBaseUrl] - Base URL for icons.
@returns {JSX.Element} The rendered ButtonGroup component.

@example
<ButtonGroup
  buttons={[
    { text: "Left", onClick: () => {} },
    { text: "Right", onClick: () => {} }
